import './App.css';

function App() {
  return (
    <div className="App">
      <p> Hi, my name is Roy </p>
      <p> I am aspiring to work in the field of Software Engineering, specializing in Artificial Intellegence!</p>
      <p>Languages:</p>
      <ul>
        <li>Python</li>
        <li>JavaScript</li>
        <li>Java</li>
        <li>C++</li>
        <li>HTML/CSS</li>
        <li>C</li>
        <li>SQL</li>
        <li>x86-64 Assembly</li>
      </ul>
    </div>
  );
}

export default App;
